const topic = $.input.topic || '';
const query = 'Recent trends, data, and expert insights about ' + topic + ' for professional audience';
return { query, topic };

const response = $.steps.exaSearch.response || {};
const results = response.data?.results || response.results || [];
let research = '';
results.forEach(function(r, i) {
  research += 'Source ' + (i + 1) + ': ' + (r.title || '') + '\n';
  research += (r.text || '').slice(0, 1500) + '\n\n';
});
return { research: research, topic: $.input.topic, tone: $.input.tone || 'professional yet conversational' };

const data = $.steps.compileResearch.output;

let prompt = 'You are a LinkedIn content strategist. Create a high-engagement LinkedIn post based on the research below.

';
prompt += 'TOPIC: ' + data.topic + '
';
prompt += 'TONE: ' + data.tone + '

';
prompt += 'RESEARCH:
' + data.research + '

';
prompt += 'INSTRUCTIONS:
';
prompt += '- Start with a strong hook (first line matters most on LinkedIn)
';
prompt += '- Use short paragraphs and line breaks for readability
';
prompt += '- Include 1-2 data points or statistics from research
';
prompt += '- End with a question or call-to-action to drive engagement
';
prompt += '- Keep under 1300 characters for optimal reach
';
prompt += '- Include relevant hashtags (3-5)

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "hook": "the opening line",
';
prompt += '  "post": "full LinkedIn post text including hook",
';
prompt += '  "hashtags": ["#hashtag1", "#hashtag2"],
';
prompt += '  "suggestedImagePrompt": "description for an accompanying image",
';
prompt += '  "bestPostingTime": "suggested day and time",
';
prompt += '  "engagementTips": ["tip1", "tip2"]
';
prompt += '}';
return { prompt };

let raw = $.steps.aiGenerate.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { hook: '', post: raw, hashtags: [], suggestedImagePrompt: '', bestPostingTime: '', engagementTips: [] }; }

const ai = $.steps.parseAI.output;
const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'LinkedIn Post Ready', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Topic:* ' + $.input.topic } });
blocks.push({ type: 'divider' });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: (ai.post || '').slice(0, 1800) } });
blocks.push({ type: 'divider' });
if (ai.hashtags && ai.hashtags.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Hashtags:* ' + ai.hashtags.join(' ') } });
}
if (ai.bestPostingTime) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Best Posting Time:* ' + ai.bestPostingTime } });
}
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Sent to ' + $.input.recipientEmail + ' | Powered by Exa + Claude AI' }] });
const fallbackText = 'LinkedIn Post Ready: ' + $.input.topic;
return { blocks, fallbackText };
